    public void update()
    {
        PurchReqTable orig = this.orig();

        next update();

        if(this.UBSProjectDim != orig.UBSProjectDim)
        {
            this.updateLinesProjectDimension();
        }
    }

    public void updateLinesProjectDimension()
    {
        PurchReqLine                        purchReqLine;
        DimensionAttributeValueSetStorage   storage;
        DimensionAttrValueLedgerOverride    override;
        UBSInventSiteCrossCompany           inventSiteCrossCompany;
        InventDim                           inventDim;

        DimensionAttributeValue             dimAttrValue = DimensionAttributeValue::find(this.UBSProjectDim);

        ttsbegin;
        while select forupdate purchReqLine 
            where purchReqLine.PurchReqTable == this.RecId
        {
            storage = DimensionAttributeValueSetStorage::find(purchReqLine.defaultDimension);
        
            if(dimAttrValue)
            {
                storage.addItem(dimAttrValue);
                purchReqLine.defaultDimension = storage.save();

                override = DimensionAttrValueLedgerOverride::findByDimensionAttrValueLedgerOverride(dimAttrValue.RecId, Ledger::current());
                inventSiteCrossCompany = UBSInventSiteCrossCompany::findByRecId(override.UBSInventSiteCCRecId);
                inventDim = purchReqLine.inventDim(true);
                inventDim.InventSiteId = inventSiteCrossCompany.SiteId;
                inventDim.update();

                purchReqLine.modifyInventDim(inventDim,fieldNum(InventDim, InventSiteId), false);

                purchReqLine.update();
            }
        }
        ttscommit;
    }

 public container UbsGetWFLastApproverAndValidationTime()
 {
     WorkflowTrackingStatusTable workflowTrackingStatusTable;
     WorkflowTrackingTable       workflowTrackingTable;
     PurchReqTable               purchReqTable;
   
     select firstonly User, CreatedDateTime from workflowTrackingTable
             order by workflowTrackingTable.RecId desc
             exists join workflowTrackingStatusTable
                 where workflowTrackingTable.WorkflowTrackingStatusTable == workflowTrackingStatusTable.RecId
                     && workflowTrackingStatusTable.ContextTableId == this.TableId
                     && workflowTrackingStatusTable.ContextRecId == this.RecId
                     && workflowTrackingTable.TrackingContext == workflowtrackingcontext::WorkItem
                     && workflowTrackingTable.TrackingType == workflowtrackingtype::Approval;

     return [workflowTrackingTable.User, workflowTrackingTable.CreatedDateTime];
 }
